            continue
        }
        graph[u].add(v to cost)
        revGraph[v].add(u to cost)
        if (cost > maxEdge) {
            maxEdge = cost
        }
    }

    val forwardReach = BooleanArray(n) { false }
    val queue: Queue<Int> = LinkedList()
    queue.add(0)
    forwardReach[0] = true
    while (queue.isNotEmpty()) {
        val u = queue.poll()
        for ((v, _) in graph[u]) {
            if (!forwardReach[v]) {
                forwardReach[v] = true
                queue.add(v)
            }
        }
    }

    if (!forwardReach[n - 1]) {
        return -1
    }

    val backwardReach = BooleanArray(n) { false }
    queue.clear()
    queue.add(n - 1)
    backwardReach[n - 1] = true
    while (queue.isNotEmpty()) {
        val v = queue.poll()
        for ((u, _) in revGraph[v]) {
            if (!backwardReach[u]) {
                backwardReach[u] = true
                queue.add(u)
            }
        }
    }

    val S = mutableSetOf<Int>()
    for (i in 0 until n) {
        if (forwardReach[i] && backwardReach[i]) {
            S.add(i)
        }
    }

    val inDeg = IntArray(n) { 0 }
    for (u in 0 until n) {
        if (u !in S) continue
        for ((v, _) in graph[u]) {
